package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.stream.JsonToken;
import com.google.gson.internal.bind.JsonTreeReader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Iterator;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;
    private JsonObject jsonObject;

    @BeforeEach
    public void setUp() throws Exception {
        jsonObject = new JsonObject();
        jsonTreeReader = new JsonTreeReader(jsonObject);

        // Use reflection to set internal state to simulate a stack with an object and an iterator
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stack = (Object[]) stackField.get(jsonTreeReader);

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);

        Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
        pathNamesField.setAccessible(true);
        String[] pathNames = (String[]) pathNamesField.get(jsonTreeReader);

        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);

        // Prepare stack: bottom = JsonObject, above = iterator of entrySet
        Iterator<?> iterator = jsonObject.entrySet().iterator();
        stack[0] = jsonObject;
        stack[1] = iterator;
        stackSizeField.setInt(jsonTreeReader, 2);

        // Set pathNames and pathIndices for index 1
        pathNames[1] = "testName";
        pathIndices[1] = 0;
    }

    @Test
    public void testEndObject_success() throws Exception {
        // Use reflection to invoke private expect method instead of mocking it
        Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
        expectMethod.setAccessible(true);

        // Spy the instance but stub the private expect method via reflection invocation inside doAnswer
        JsonTreeReader spyReader = spy(jsonTreeReader);

        // Stub the private expect method by intercepting calls to endObject and invoking expect via reflection manually
        doAnswer(invocation -> {
            // call the real endObject but replacing expect call by reflection manually
            // so call expect manually here to simulate expect(JsonToken.END_OBJECT)
            expectMethod.invoke(spyReader, JsonToken.END_OBJECT);

            // then execute the rest of endObject normally by calling real method without expect call
            // To do this, we invoke the original endObject method without the expect call.
            // But since expect is the first line in endObject, we must call the real method normally.
            // Instead, we just call real method normally (since expect is private, it will be called)
            // But to avoid double calling expect, we create a subclass or use reflection to call the method body without expect.
            // To simplify, just call real method normally and do not stub expect:
            // So we do nothing here and call real method normally below.

            // This doAnswer is only to intercept expect call in Mockito, but since expect is private,
            // Mockito cannot stub it anyway, so we just do nothing here.
            return null;
        }).when(spyReader).endObject();

        // Because we cannot stub private expect, instead call real endObject directly:
        // So discard above doAnswer and just call real method directly:
        spyReader = spy(jsonTreeReader); // reset spy
        doCallRealMethod().when(spyReader).endObject();
        spyReader.endObject();

        // Verify pathNames[stackSize - 1] is null
        Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
        pathNamesField.setAccessible(true);
        String[] pathNames = (String[]) pathNamesField.get(spyReader);

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        int stackSize = stackSizeField.getInt(spyReader);
        assertNull(pathNames[stackSize - 1]);

        // Verify stackSize decreased by 2
        assertEquals(0, stackSize);

        // Verify pathIndices incremented if stackSize > 0 (should not increment here because stackSize=0)
        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = (int[]) pathIndicesField.get(spyReader);

        // Since stackSize is now 0, no increment expected, so original pathIndices[stackSize - 1] not applicable
        // Just check that no exception thrown and stackSize is 0
        assertEquals(0, stackSizeField.getInt(spyReader));
    }

    @Test
    public void testEndObject_stackSizeGreaterThanZeroIncrementsPathIndices() throws Exception {
        // Setup stackSize to 3 so after popping twice stackSize = 1, pathIndices[0] should increment
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stack = (Object[]) stackField.get(jsonTreeReader);

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);

        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);

        Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
        pathNamesField.setAccessible(true);
        String[] pathNames = (String[]) pathNamesField.get(jsonTreeReader);

        // Add one more element to stack
        stack[2] = new Object();
        stackSizeField.setInt(jsonTreeReader, 3);

        // Set pathNames and pathIndices for top two stack elements
        pathNames[2] = "name2";
        pathNames[1] = "name1";
        pathIndices[1] = 5;
        pathIndices[0] = 10;

        // Spy and call real method
        JsonTreeReader spyReader = spy(jsonTreeReader);

        // Call real endObject method (cannot mock private expect)
        doCallRealMethod().when(spyReader).endObject();
        spyReader.endObject();

        // After endObject:
        // stackSize should be 1 (3 - 2)
        int newStackSize = stackSizeField.getInt(spyReader);
        assertEquals(1, newStackSize);

        // pathNames[newStackSize - 1] should be null
        assertNull(pathNames[newStackSize - 1]);

        // pathIndices[newStackSize - 1] should be incremented by 1 (from 10 to 11)
        assertEquals(11, pathIndices[newStackSize - 1]);
    }
}
